222	
223	static int find_rx_slot(UART_HandleTypeDef *huart)
224	{
225	    if (huart == NULL) return -1;
226	    /* Find existing slot */
227	    for (int i = 0; i < MOCK_UART_RX_SLOTS; i++) {
228	        if (mock_uart_rx[i].uart_id == huart->id && mock_uart_rx[i].head != mock_uart_rx[i].tail) {
229	            return i;
230	        }
231	        if (mock_uart_rx[i].uart_id == huart->id) {
232	            return i;
233	        }
234	    }
235	    /* Find empty slot */
236	    for (int i = 0; i < MOCK_UART_RX_SLOTS; i++) {
237	        if (mock_uart_rx[i].uart_id == 0) {
238	            mock_uart_rx[i].uart_id = huart->id;
239	            return i;
240	        }
241	    }
242	    return -1;
243	}
