245	void mock_uart_rx_load(UART_HandleTypeDef *huart, const uint8_t *data, uint16_t len)
246	{
247	    int slot = find_rx_slot(huart);
248	    if (slot < 0) return;
249	    mock_uart_rx[slot].uart_id = huart->id;
250	    for (uint16_t i = 0; i < len; i++) {
251	        uint16_t next = (mock_uart_rx[slot].head + 1) % MOCK_UART_RX_BUF_SIZE;
252	        if (next == mock_uart_rx[slot].tail) break;  /* Buffer full */
253	        mock_uart_rx[slot].buf[mock_uart_rx[slot].head] = data[i];
254	        mock_uart_rx[slot].head = next;
255	    }
256	}
