258	void mock_uart_rx_clear(UART_HandleTypeDef *huart)
259	{
260	    int slot = find_rx_slot(huart);
261	    if (slot < 0) return;
262	    mock_uart_rx[slot].head = 0;
263	    mock_uart_rx[slot].tail = 0;
264	}
