266	HAL_StatusTypeDef HAL_UART_Receive(UART_HandleTypeDef *huart, uint8_t *pData,
267	                                    uint16_t Size, uint32_t Timeout)
268	{
269	    (void)Timeout;
270	    int slot = find_rx_slot(huart);
271	    if (slot < 0) return HAL_TIMEOUT;
272	
273	    for (uint16_t i = 0; i < Size; i++) {
274	        if (mock_uart_rx[slot].head == mock_uart_rx[slot].tail) {
275	            return HAL_TIMEOUT;  /* No more data */
276	        }
277	        pData[i] = mock_uart_rx[slot].buf[mock_uart_rx[slot].tail];
278	        mock_uart_rx[slot].tail = (mock_uart_rx[slot].tail + 1) % MOCK_UART_RX_BUF_SIZE;
279	    }
280	
281	    spy_push((SpyRecord){
282	        .type  = SPY_UART_RX,
283	        .port  = NULL,
284	        .pin   = Size,
285	        .value = Timeout,
286	        .extra = huart
287	    });
288	
289	    return HAL_OK;
290	}
