2	 * test_gap3_overtemp_emergency_stop.c
3	 *
4	 * Safety bug: handleSystemError() did not escalate ERROR_TEMPERATURE_HIGH
5	 * (or ERROR_WATCHDOG_TIMEOUT) to Emergency_Stop().
6	 *
7	 * Before fix:  The critical-error gate was
8	 *                if (error >= ERROR_RF_PA_OVERCURRENT &&
9	 *                    error <= ERROR_POWER_SUPPLY) { Emergency_Stop(); }
10	 *              So overtemp (code 14) and watchdog timeout (code 16) fell
11	 *              through to attemptErrorRecovery()'s default branch (log and
12	 *              continue), leaving the 10 W GaN PAs biased at >75 °C.
13	 *
14	 * After fix:   The gate also matches ERROR_TEMPERATURE_HIGH and
15	 *              ERROR_WATCHDOG_TIMEOUT, so thermal and watchdog faults
16	 *              latch Emergency_Stop() exactly like PA overcurrent.
17	 *
18	 * Test strategy:
19	 *   Replicate the critical-error predicate and assert that every error
20	 *   enum value which threatens RF/power safety is accepted, and that the
21	 *   non-critical ones (comm, sensor, memory) are not.
22	 ******************************************************************************/
23	#include <assert.h>
24	#include <stdio.h>
25	
26	/* Mirror of SystemError_t from main.cpp (keep in lockstep). */
27	typedef enum {
28	    ERROR_NONE = 0,
29	    ERROR_AD9523_CLOCK,
30	    ERROR_ADF4382_TX_UNLOCK,
31	    ERROR_ADF4382_RX_UNLOCK,
32	    ERROR_ADAR1000_COMM,
33	    ERROR_ADAR1000_TEMP,
34	    ERROR_IMU_COMM,
35	    ERROR_BMP180_COMM,
36	    ERROR_GPS_COMM,
37	    ERROR_RF_PA_OVERCURRENT,
38	    ERROR_RF_PA_BIAS,
39	    ERROR_STEPPER_MOTOR,
40	    ERROR_FPGA_COMM,
41	    ERROR_POWER_SUPPLY,
42	    ERROR_TEMPERATURE_HIGH,
43	    ERROR_MEMORY_ALLOC,
44	    ERROR_WATCHDOG_TIMEOUT
45	} SystemError_t;
46	
47	/* Extracted post-fix predicate: returns 1 when Emergency_Stop() must fire. */
48	static int triggers_emergency_stop(SystemError_t e)
49	{
50	    return ((e >= ERROR_RF_PA_OVERCURRENT && e <= ERROR_POWER_SUPPLY) ||
51	            e == ERROR_TEMPERATURE_HIGH ||
52	            e == ERROR_WATCHDOG_TIMEOUT);
53	}
54	
55	int main(void)
56	{
57	    printf("=== Safety fix: overtemp / watchdog -> Emergency_Stop() ===\n");
58	
59	    /* --- Errors that MUST latch Emergency_Stop --- */
60	    printf("  Test 1: ERROR_RF_PA_OVERCURRENT triggers... ");
61	    assert(triggers_emergency_stop(ERROR_RF_PA_OVERCURRENT));
62	    printf("PASS\n");
63	
