77	    assert(triggers_emergency_stop(ERROR_POWER_SUPPLY));
78	    printf("PASS\n");
79	
80	    printf("  Test 6: ERROR_TEMPERATURE_HIGH triggers (regression)... ");
81	    assert(triggers_emergency_stop(ERROR_TEMPERATURE_HIGH));
82	    printf("PASS\n");
83	
84	    printf("  Test 7: ERROR_WATCHDOG_TIMEOUT triggers (regression)... ");
85	    assert(triggers_emergency_stop(ERROR_WATCHDOG_TIMEOUT));
86	    printf("PASS\n");
87	
88	    /* --- Errors that MUST NOT escalate (recoverable / informational) --- */
89	    printf("  Test 8: ERROR_NONE does not trigger... ");
