66	int main(void)
67	{
68	    printf("=== Bug #2 (FIXED): AD9523 single setup call ===\n");
69	
70	    spy_reset();
71	    int ret = configure_ad9523_extracted();
72	    assert(ret == 0);
73	
74	    /* ---- Test A: ad9523_setup was called exactly ONCE ---- */
75	    int setup_count = spy_count_type(SPY_AD9523_SETUP);
76	    printf("  SPY_AD9523_SETUP records: %d (expected 1)\n", setup_count);
77	    assert(setup_count == 1);
78	    printf("  PASS: ad9523_setup() called exactly once\n");
79	
80	    /* ---- Test B: Reset release occurs BEFORE the setup call ---- */
81	    int setup_idx = spy_find_nth(SPY_AD9523_SETUP, 0);
82	
83	    /* Find the GPIO write for GPIOF, AD9523_RESET_Pin, SET */
84	    int reset_gpio_idx = -1;
85	    for (int i = 0; i < setup_idx; i++) {
86	        const SpyRecord *r = spy_get(i);
87	        if (r && r->type == SPY_GPIO_WRITE &&
88	            r->port == GPIOF &&
89	            r->pin == AD9523_RESET_Pin &&
90	            r->value == GPIO_PIN_SET) {
91	            reset_gpio_idx = i;
92	            break;
93	        }
94	    }
95	
96	    printf("  Reset release at spy index %d, setup at %d\n",
97	           reset_gpio_idx, setup_idx);
98	    assert(reset_gpio_idx >= 0);
99	    assert(reset_gpio_idx < setup_idx);
100	    printf("  PASS: Reset released BEFORE setup call (correct order)\n");
101	
102	    printf("=== Bug #2 (FIXED): ALL TESTS PASSED ===\n\n");
103	    return 0;
104	}
